insert into payComplete (
    uId, cNum, cUid, cTitle, pNum, pQty, payDate, createdDate, createdBy, updatedDate, updatedBy
) values (
    #{uId}, #{cNum}, #{cUid}, #{cTitle}, #{pNum}, #{pQty}, now(),
    current_timestamp, coalesce(#{createdBy}, #{uId}), current_timestamp, coalesce(#{updatedBy}, #{uId})
)
